INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('sibele', '{"name":"Cibele","mapped_name":null,"birth_date":"1988-04-30","profession":"Diretor Executivo","sports_history":"Helmuth: Quando mais jovem praticou musculação (há mais de 10 anos), após entrar na faculdade ficou difícil conciliar, ano passado ficou um ano na vida \"fit\", perdeu 12kg em aprox 3~4 meses. Fazia treinos \"HIIT\" e no app da Apple.\nCurtia treinar musculação. Prioridade é perder peso.\nAcademia muito cheia e o instrutor não dava muito atenção.\n\n\nCibele: também treinou há algum tempo atrás, (mãe de 2), treinava em casa cuidando da alimentação e conseguiu perder bastante peso no período. Quando a filha começou a escolinha conseguiu se manter quase 2 anos treinando direto na academia.","injuries":["H: nada","excelente.","C: nada","excelente."],"health_conditions":["Nada."],"medications":["H: Remédio pro colesterol. Nebloc (coração","diminuição do ritmo cardíaco)","zoopiden e donaren esporadicamente.","C: nada."],"current_practice":"H: 1 ano parado, e esteve fazendo HIIT desde o início da pandemia. Musculação não faz há 1 ano também.\n\nC: treinou reuglharmente até novembro, desde o início da pandemia. 2 meses parada.","goal":"H: ser mais disciplinado, estar mais vinculado com um estilo de vida saudável. Saúde.\n\nC: busca desenvolver mais a musculatura aliada a definição.","weekly_frequency":null,"session_duration":null,"gender":"F","experience_level":"intermediário","form_timestamp":"2022/02/02 1:36:42 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Agachamento Bulgaro","method":"Tradicional 6-8","sets":"","reps":"","interval":"1''","observations":""},{"name":"Passada Barra Costas","method":"Tradicional 16-20","sets":"","reps":"16-20","interval":"1''30\"","observations":""},{"name":"Agachamento Livre","method":"Tradicional 6-8","sets":"","reps":"6+8","interval":"2''","observations":""},{"name":"Cadeira Extensora","method":"DropSet     12 + 8","sets":"","reps":"12 + 8","interval":"1''","observations":""},{"name":"Leg 45°","method":"Cluster Set\n8+8","sets":"","reps":"8+8","interval":"1''30\"","observations":"Cluster set consiste em realizar as primeiras repetições, fazer um intervalo curto de 20\" e depois realizar as próximas para fechar a série"},{"name":"Agachamento Bulgaro Halteres Parcial  (70º)","method":"Tradicional","sets":"","reps":"","interval":"1''30\"","observations":""},{"name":"Cadeira Extensora Parcial (90-60º) + Agachamento Peso Corporal","method":"Pré Exaustão","sets":"","reps":"10 + 20","interval":"1''","observations":"Sair da extensora e realizar agachamento parcial com o peso do corpo"},{"name":"Leg Press + Agachamento Isométrico","method":"Tradicional","sets":"","reps":"12 + 30''''","interval":"1''","observations":"Cuidar para não fazer uma extensão dos joelhos brusca, isometria do agachamento um pouco acima dos 90°"},{"name":"Cadeira Abdutora Tronco inclinado a Frente + Abdominal Remada","method":"Tradicional","sets":"","reps":"12-16","interval":"1''30\"","observations":"Apoiar a lateral do joelho no aparador da cadeira, inclinar o tronco bem a frente e realizar o afastamento das pernas"}]},"B":{"focus":"","exercises":[{"name":"Remada Curvada Supinada Barra + Stiff","method":"Bi-Set","sets":"","reps":"8+12","interval":"1''30''''","observations":"Se necessário, usar um strap para sustentação da barra nas mãos"},{"name":"Crucifixo Inverso + Elevação Lateral","method":"Bi-Set","sets":"","reps":"12+12","interval":"1''30\"","observations":"Realizar o Crucifixo Inverso e a Elevação com a mesma carga, sem intervalo entre eles"},{"name":"Agachamento Cálice (70º) + Prancha Toque no Ombro","method":"Bi-Set","sets":"","reps":"15 agachamentos + 30 toques no ombro alternados em prancha","interval":"1''","observations":""}]},"C":{"focus":"","exercises":[{"name":"Mesa Flexora Parcial (90-60º)","method":"Tradicional","sets":"","reps":"12-16","interval":"1''30\"","observations":""},{"name":"Stiff","method":"Tradicional","sets":"","reps":"10-14","interval":"1''30\"","observations":""},{"name":"Hip Thrust Barra","method":"Tradicional","sets":"","reps":"","interval":"1''30\"","observations":""},{"name":"Glúteo 4 Apoios Caneleira","method":"Tradicional","sets":"","reps":"1''30\"","interval":"","observations":""}]}}'::jsonb, ARRAY['A','B','C']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;